    public void Move_DestinationEscapingRoot_ThrowsArgumentException()
    {
        var (service, _) = CreateService();

        Assert.Throws<ArgumentException>(() =>
            service.Move(new MoveRequest("a.txt", "../escape/x.txt")));
    }

